using System;
using System.Collections.Generic;
using System.Threading.Tasks;
using Azure.Core;
using Azure.Core.TestFramework;
using Azure.ResourceManager.DnsResolver;
using Azure.ResourceManager.DnsResolver.Models;
using Azure.ResourceManager.Network;
using Azure.ResourceManager.Network.Models;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.DnsResolver.Tests.Samples
{
    public class Sample1_DnsResolver : SamplesBase<DnsResolverManagementTestEnvironment>
    {
        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateDnsResolver()
        {
            #region Snippet:CreateDnsResolver
            // Authenticate and get the default subscription
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();

            // Create a resource group
            ResourceGroupResource resourceGroup = (await subscription.GetResourceGroups()
                .CreateOrUpdateAsync(WaitUntil.Completed, "myResourceGroup",
                    new ResourceGroupData(AzureLocation.EastUS))).Value;

            // Reference an existing virtual network
            ResourceIdentifier vnetId = new ResourceIdentifier(
                $"/subscriptions/{subscription.Id.SubscriptionId}/resourceGroups/myResourceGroup/providers/Microsoft.Network/virtualNetworks/myVNet");

            // Create the DNS resolver
            DnsResolverCollection resolvers = resourceGroup.GetDnsResolvers();
            DnsResolverData resolverData = new DnsResolverData(AzureLocation.EastUS)
            {
                VirtualNetwork = new WritableSubResource { Id = vnetId }
            };
            DnsResolverResource resolver = (await resolvers.CreateOrUpdateAsync(
                WaitUntil.Completed, "myDnsResolver", resolverData)).Value;

            Console.WriteLine($"Created DNS Resolver: {resolver.Data.Name}");
            #endregion
        }

        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateInboundEndpoint()
        {
            #region Snippet:CreateInboundEndpoint
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            ResourceGroupResource resourceGroup = await subscription.GetResourceGroups()
                .GetAsync("myResourceGroup");

            DnsResolverResource resolver = await resourceGroup.GetDnsResolvers()
                .GetAsync("myDnsResolver");

            ResourceIdentifier subnetId = new ResourceIdentifier(
                $"/subscriptions/{subscription.Id.SubscriptionId}/resourceGroups/myResourceGroup/providers/Microsoft.Network/virtualNetworks/myVNet/subnets/inboundSubnet");

            DnsResolverInboundEndpointData inboundData = new DnsResolverInboundEndpointData(
                AzureLocation.EastUS,
                new List<InboundEndpointIPConfiguration>
                {
                    new InboundEndpointIPConfiguration(new WritableSubResource { Id = subnetId })
                });

            DnsResolverInboundEndpointResource inboundEndpoint = (await resolver.GetDnsResolverInboundEndpoints()
                .CreateOrUpdateAsync(WaitUntil.Completed, "myInboundEndpoint", inboundData)).Value;

            Console.WriteLine($"Created Inbound Endpoint: {inboundEndpoint.Data.Name}");
            #endregion
        }

        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateForwardingRuleset()
        {
            #region Snippet:CreateForwardingRuleset
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            ResourceGroupResource resourceGroup = await subscription.GetResourceGroups()
                .GetAsync("myResourceGroup");

            ResourceIdentifier outboundEndpointId = new ResourceIdentifier(
                $"/subscriptions/{subscription.Id.SubscriptionId}/resourceGroups/myResourceGroup/providers/Microsoft.Network/dnsResolvers/myDnsResolver/outboundEndpoints/myOutboundEndpoint");

            DnsForwardingRulesetData rulesetData = new DnsForwardingRulesetData(
                AzureLocation.EastUS,
                new List<WritableSubResource> { new WritableSubResource { Id = outboundEndpointId } });

            DnsForwardingRulesetResource ruleset = (await resourceGroup.GetDnsForwardingRulesets()
                .CreateOrUpdateAsync(WaitUntil.Completed, "myForwardingRuleset", rulesetData)).Value;

            Console.WriteLine($"Created Forwarding Ruleset: {ruleset.Data.Name}");
            #endregion
        }

        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateForwardingRule()
        {
            #region Snippet:CreateForwardingRule
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            ResourceGroupResource resourceGroup = await subscription.GetResourceGroups()
                .GetAsync("myResourceGroup");

            DnsForwardingRulesetResource ruleset = await resourceGroup.GetDnsForwardingRulesets()
                .GetAsync("myForwardingRuleset");

            DnsForwardingRuleData ruleData = new DnsForwardingRuleData(
                domainName: "contoso.com.",
                targetDnsServers: new List<TargetDnsServer>
                {
                    new TargetDnsServer("10.0.0.4", 53)
                });

            DnsForwardingRuleResource rule = (await ruleset.GetDnsForwardingRules()
                .CreateOrUpdateAsync(WaitUntil.Completed, "myForwardingRule", ruleData)).Value;

            Console.WriteLine($"Created Forwarding Rule: {rule.Data.Name}");
            #endregion
        }
    }
}
```

